const d = $json;
const perLlm = d.per_llm || {};
const lines = Object.keys(perLlm).map(name => {
  const e = perLlm[name];
  const flag = e.recommended === true ? ':white_check_mark:' : ':x:';
  const rank = e.rank != null ? ` (rank ${e.rank})` : '';
  return `${flag} *${name}*${rank}`;
});
const header = d.slipped
  ? `:rotating_light: *${d.brand}* is NOT recommended by any measured AI assistant.`
  : d.overtaken
    ? `:warning: *${d.brand}* was overtaken by a competitor in at least one AI assistant.`
    : `:tada: *${d.brand}* is holding its AI-visibility position.`;
const sov = d.overall && d.overall.share_of_voice_pct != null
  ? `\nShare of voice: *${d.overall.share_of_voice_pct}%*`
  : '';
const score = `\nRecommended by *${(d.overall||{}).recommended_count||0}/${(d.overall||{}).llm_count||0}* assistants.`;
const gaps = Array.isArray(d.gaps) && d.gaps.length
  ? `\n\n*Missing from prompts:*\n` + d.gaps.slice(0,5).map(g => `• ${typeof g === 'string' ? g : (g.prompt || g.query || JSON.stringify(g))}`).join('\n')
  : '';
return { digest: `${header}${score}${sov}\n\n${lines.join('\n')}${gaps}`, slipped: d.slipped, overtaken: d.overtaken };
